import java.util.Scanner;

public class SecureBufferHandling {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Validate input length to prevent buffer overflow
        if (userInput.length() > 10) {
            System.out.println("Input exceeds maximum allowed length. Exiting...");
            return;
        }

        // Safe copy using appropriate size for buffer
        byte[] buffer = new byte[userInput.length()];
        System.arraycopy(userInput.getBytes(), 0, buffer, 0, userInput.length());

        System.out.println("Secure buffer handling completed.");
    }
}

